parameters.jsCode:
// Parse milestone data and generate notification content
const webhookData = $('Webhook: Project Milestone Reached').item.json;
const projectData = $input.item.json;

// Milestone information
const milestoneType = webhookData.milestone_type; // 'kickoff', 'design_approved', 'development_complete', 'testing', 'launch', 'custom'
const milestoneTitle = webhookData.milestone_title || '';
const milestoneDescription = webhookData.milestone_description || '';
const nextSteps = webhookData.next_steps || '';
const attachmentUrls = webhookData.attachments || [];

// Generate milestone-specific content
function getMilestoneContent(type) {
  const contents = {
    'kickoff': {
      emoji: '🚀',
      subject: 'Project Kickoff - Let\'s Get Started!',
      title: 'Project Kickoff Complete',
      message: `We're excited to officially kick off your project! Our team has reviewed all requirements and we're ready to begin.`,
      color: 3447003 // Blue
    },
    'design_approved': {
      emoji: '🎨',
      subject: 'Design Approved - Moving to Development',
      title: 'Design Phase Complete',
      message: `Great news! Your design has been approved and we're moving forward with development.`,
      color: 10181046 // Purple
    },
    'development_complete': {
      emoji: '💻',
      subject: 'Development Complete - Ready for Review',
      title: 'Development Phase Complete',
      message: `Development is complete! Your project is ready for testing and review.`,
      color: 3066993 // Green
    },
    'testing': {
      emoji: '🧪',
      subject: 'Testing Phase - Quality Assurance',
      title: 'Testing in Progress',
      message: `We're thoroughly testing your project to ensure everything works perfectly.`,
      color: 15844367 // Yellow
    },
    'launch': {
      emoji: '🎉',
      subject: 'Launch Day - Your Project is Live!',
      title: 'Project Successfully Launched',
      message: `Congratulations! Your project is now live and ready for the world to see.`,
      color: 15158332 // Red/Orange
    },
    'custom': {
      emoji: '📢',
      subject: milestoneTitle || 'Project Update',
      title: milestoneTitle || 'Project Milestone',
      message: milestoneDescription || 'We have an update on your project.',
      color: 9807270 // Gray
    }
  };

  return contents[type] || contents['custom'];
}

const content = getMilestoneContent(milestoneType);

// Calculate project progress
const progressPercentage = projectData.progress_percentage || 0;
const progressBar = '█'.repeat(Math.floor(progressPercentage / 10)) + '░'.repeat(10 - Math.floor(progressPercentage / 10));

// Format dates
const startDate = new Date(projectData.start_date).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const targetDate = new Date(projectData.target_completion_date).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

return {
  json: {
    // Project data
    project_id: projectData.id,
    project_name: projectData.project_name,
    client_name: projectData.client_name || `${projectData.first_name} ${projectData.last_name}`,
    client_email: projectData.client_email || projectData.lead_email,
    company: projectData.company || '',

    // Milestone data
    milestone_type: milestoneType,
    milestone_title: content.title,
    milestone_emoji: content.emoji,
    milestone_message: content.message,
    milestone_description: milestoneDescription,
    next_steps: nextSteps,
    attachments: attachmentUrls,

    // Email content
    email_subject: `${content.emoji} ${content.subject}`,

    // Progress data
    progress_percentage: progressPercentage,
    progress_bar: progressBar,
    project_status: projectData.status,
    start_date: startDate,
    target_date: targetDate,

    // Discord embed color
    discord_color: content.color
  }
};

